// Nodo: "Ensure Single Output" - VERSIÓN CORREGIDA PARA VELAS
const allItems = $input.all();

console.log(`📦 Ensure Single Output: Recibidos ${allItems.length} items`);

// Inicializar objeto combinado
const combined = {
    timestamp: new Date().toISOString()
};

// Arrays para acumular datos
let allCandles = [];

// Procesar CADA ITEM
for (let i = 0; i < allItems.length; i++) {
    const data = allItems[i].json;

    console.log(`\n--- Procesando Item ${i} ---`);

    // ============================================
    // 1. PRECIO (bid/ask) - solo del primer item que lo tenga
    // ============================================
    if (data.bid !== undefined && combined.bid === undefined) {
        combined.bid = data.bid;
        combined.ask = data.ask;
        console.log(`  ✅ Precio: bid ${data.bid}, ask ${data.ask}`);
    }

    // ============================================
    // 2. VELAS - CADA ITEM PUEDE SER UNA VELA INDIVIDUAL
    // ============================================

    // Si el item tiene estructura de vela (close, open, high, low)
    if (data.close !== undefined && data.open !== undefined) {
        allCandles.push({
            time: data.time,
            open: data.open,
            high: data.high,
            low: data.low,
            close: data.close,
            tick_volume: data.tick_volume,
            spread: data.spread,
            real_volume: data.real_volume
        });
        console.log(`  ✅ Vela individual: ${data.time} close=${data.close}`);
    }

    // Si el item tiene un array de velas
    if (data.candles && Array.isArray(data.candles) && data.candles.length > 0) {
        allCandles = allCandles.concat(data.candles);
        console.log(`  ✅ Velas (array): ${data.candles.length} items`);
    }

    // Si el item es un array de velas directamente
    if (Array.isArray(data) && data.length > 0 && data[0].close !== undefined) {
        allCandles = allCandles.concat(data);
        console.log(`  ✅ Velas (array directo): ${data.length} items`);
    }
}

// ============================================
// ORDENAR VELAS POR TIEMPO (más reciente primero o más antigua)
// ============================================
if (allCandles.length > 0) {
    // Ordenar por tiempo (más antigua primero para análisis)
    allCandles.sort((a, b) => {
        const dateA = new Date(a.time);
        const dateB = new Date(b.time);
        return dateA - dateB;
    });

    combined.candles = allCandles;
    console.log(`\n📊 Total velas recolectadas: ${allCandles.length}`);
    console.log(`   - Primera: ${allCandles[0]?.time} close=${allCandles[0]?.close}`);
    console.log(`   - Última: ${allCandles[allCandles.length-1]?.time} close=${allCandles[allCandles.length-1]?.close}`);
} else {
    combined.candles = [];
    console.log(`\n⚠️ No se encontraron velas`);
}

// ============================================
// DETERMINAR EL SÍMBOLO POR EL PRECIO
// ============================================
let symbol = "EURUSD";
if (combined.bid) {
    if (combined.bid > 1.0 && combined.bid < 1.2) symbol = "EURUSD";
    else if (combined.bid > 1.2 && combined.bid < 1.4) symbol = "GBPUSD";
    else if (combined.bid > 140 && combined.bid < 170) symbol = "USDJPY";
    else if (combined.bid > 0.85 && combined.bid < 1.0) symbol = "USDCHF";
}

combined.symbol = symbol;

console.log(`\n📦 RESULTADO FINAL:`);
console.log(`   - symbol: ${combined.symbol}`);
console.log(`   - bid: ${combined.bid}`);
console.log(`   - candles: ${combined.candles.length}`);

return [{ json: combined }];
